20→    <form
21→        method="post"
22→        action="/contexts"
23→        class="context-add"
24→        hx-post="/contexts"
25→        hx-target="#context-list"
26→        hx-swap="beforeend"
27→        hx-on::after-request="if(event.detail.successful) this.reset(); this.querySelector('#context-name').focus();"
28→    >
29→        <label for="context-name">Add context</label>
30→        <input
31→            type="text"
32→            id="context-name"
33→            name="name"
34→            placeholder="e.g., @office"
35→            maxlength="50"
36→            autocomplete="off"
37→            class="context-add__input"
38→        >
39→        <button type="submit" class="context-add__submit">Add</button>
40→    </form>
41→
42→    {% if contexts.is_empty() %}
43→    <div class="contexts__empty-state" id="contexts-empty-state">
44→        <p>No contexts yet. Add one above, or they will be created automatically when you register.</p>
45→    </div>
46→    {% endif %}
47→    <ul class="contexts__list" role="list" id="context-list"{% if contexts.is_empty() %} hidden{% endif %}>
48→        {% for context in contexts %}
49→        {% include "context_item.html" %}
50→        {% endfor %}
51→    </ul>
52→</div>
53→{% endblock %}
54→
55→{% block scripts %}
56→<script>
57→document.getElementById('context-list').addEventListener('htmx:afterSwap', function() {
58→    var list = document.getElementById('context-list');
59→    var emptyState = document.getElementById('contexts-empty-state');
