use chrono::{DateTime, Utc};
use uuid::Uuid;

use super::user::UserId;

const MAX_CONTEXT_NAME_LENGTH: usize = 50;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ContextId(Uuid);

impl Default for ContextId {
    fn default() -> Self {
        Self::new()
    }
}

impl ContextId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }

    pub fn from_uuid(uuid: Uuid) -> Self {
        Self(uuid)
    }

    pub fn as_uuid(&self) -> &Uuid {
        &self.0
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct ContextName(String);

impl ContextName {
    pub fn parse(input: String) -> Result<Self, ContextNameError> {
        let trimmed = input.trim().to_string();
        if trimmed.is_empty() {
            return Err(ContextNameError::Empty);
        }
        if trimmed.len() > MAX_CONTEXT_NAME_LENGTH {
            return Err(ContextNameError::TooLong {
                max: MAX_CONTEXT_NAME_LENGTH,
                actual: trimmed.len(),
            });
        }
        Ok(Self(trimmed))
    }

    pub fn as_str(&self) -> &str {
        &self.0
    }
}

#[derive(Debug, thiserror::Error, PartialEq)]
pub enum ContextNameError {
    #[error("Context name cannot be empty")]
    Empty,
    #[error("Context name too long (max {max}, got {actual})")]
    TooLong { max: usize, actual: usize },
}

#[derive(Debug, Clone)]
pub struct Context {
    id: ContextId,
    user_id: UserId,
    name: ContextName,
    position: i32,
    created_at: DateTime<Utc>,
}

impl Context {
    pub fn new(user_id: UserId, name: ContextName, position: i32) -> Self {
        Self {
            id: ContextId::new(),
            user_id,
            name,
            position,
            created_at: Utc::now(),
        }
    }

    pub fn from_parts(
        id: ContextId,
        user_id: UserId,
        name: ContextName,
        position: i32,
        created_at: DateTime<Utc>,
    ) -> Self {
        Self {
            id,
            user_id,
            name,
            position,
            created_at,
        }
    }

    pub fn id(&self) -> &ContextId {
        &self.id
    }

    pub fn user_id(&self) -> &UserId {
        &self.user_id
    }

    pub fn name(&self) -> &ContextName {
        &self.name
    }

    pub fn position(&self) -> i32 {
        self.position
    }

    pub fn created_at(&self) -> &DateTime<Utc> {
        &self.created_at
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // ---- ContextId ----

    #[test]
    fn context_id_is_unique() {
        let id1 = ContextId::new();
        let id2 = ContextId::new();
        assert_ne!(id1, id2);
    }

    #[test]
    fn context_id_from_uuid_roundtrips() {
        let uuid = Uuid::new_v4();
        let id = ContextId::from_uuid(uuid);
        assert_eq!(id.as_uuid(), &uuid);
    }

    // ---- ContextName ----

    #[test]
    fn valid_context_name_is_accepted() {
        let result = ContextName::parse("@computer".to_string());
        assert!(result.is_ok());
        assert_eq!(result.unwrap().as_str(), "@computer");
    }

    #[test]
    fn context_name_without_at_prefix_is_accepted() {
        let result = ContextName::parse("office".to_string());
        assert!(result.is_ok());
        assert_eq!(result.unwrap().as_str(), "office");
    }

    #[test]
    fn empty_context_name_is_rejected() {
        let result = ContextName::parse("".to_string());
        assert_eq!(result, Err(ContextNameError::Empty));
    }

    #[test]
    fn whitespace_only_context_name_is_rejected() {
        let result = ContextName::parse("   ".to_string());
        assert_eq!(result, Err(ContextNameError::Empty));
    }

    #[test]
    fn context_name_is_trimmed() {
        let result = ContextName::parse("  @home  ".to_string());
        assert!(result.is_ok());
        assert_eq!(result.unwrap().as_str(), "@home");
    }

    #[test]
    fn context_name_at_max_length_is_accepted() {
        let name = "a".repeat(MAX_CONTEXT_NAME_LENGTH);
        let result = ContextName::parse(name.clone());
        assert!(result.is_ok());
        assert_eq!(result.unwrap().as_str(), name);
    }

    #[test]
    fn context_name_exceeding_max_length_is_rejected() {
        let name = "a".repeat(MAX_CONTEXT_NAME_LENGTH + 1);
        let result = ContextName::parse(name);
        assert_eq!(
            result,
            Err(ContextNameError::TooLong {
                max: MAX_CONTEXT_NAME_LENGTH,
                actual: MAX_CONTEXT_NAME_LENGTH + 1,
            })
        );
    }

    // ---- Context ----

    #[test]
    fn new_context_has_name_user_and_position() {
        let user_id = UserId::new();
        let name = ContextName::parse("@computer".to_string()).unwrap();
        let context = Context::new(user_id.clone(), name, 0);

        assert_eq!(context.name().as_str(), "@computer");
        assert_eq!(context.user_id(), &user_id);
        assert_eq!(context.position(), 0);
    }

    #[test]
    fn context_from_parts_preserves_fields() {
        let id = ContextId::new();
        let user_id = UserId::new();
        let name = ContextName::parse("@home".to_string()).unwrap();
        let now = Utc::now();

        let context = Context::from_parts(id.clone(), user_id.clone(), name, 3, now);

        assert_eq!(context.id(), &id);
        assert_eq!(context.user_id(), &user_id);
        assert_eq!(context.name().as_str(), "@home");
        assert_eq!(context.position(), 3);
        assert_eq!(context.created_at(), &now);
    }
}

use chrono::{DateTime, Utc};
use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::{Context, ContextId, ContextName, UserId};

struct ContextRecord {
    id: Uuid,
    user_id: Uuid,
    name: String,
    position: i32,
    created_at: DateTime<Utc>,
}

impl ContextRecord {
    fn into_domain(self) -> Context {
        let id = ContextId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let name = ContextName::parse(self.name).expect("stored context name should be valid");

        Context::from_parts(id, user_id, name, self.position, self.created_at)
    }
}

pub async fn insert_context(pool: &PgPool, context: &Context) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"INSERT INTO contexts (id, user_id, name, position, created_at)
           VALUES ($1, $2, $3, $4, $5 :: timestamptz)"#,
        context.id().as_uuid(),
        context.user_id().as_uuid(),
        context.name().as_str(),
        context.position(),
        context.created_at() as &DateTime<Utc>,
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_contexts_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<Context>, sqlx::Error> {
    let records = sqlx::query_as!(
        ContextRecord,
        r#"SELECT id, user_id, name, position,
           created_at as "created_at: DateTime<Utc>"
           FROM contexts WHERE user_id = $1 ORDER BY position ASC, name ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records
        .into_iter()
        .map(|r: ContextRecord| r.into_domain())
        .collect())
}

pub async fn find_context_by_id(
    pool: &PgPool,
    context_id: &ContextId,
) -> Result<Option<Context>, sqlx::Error> {
    let record: Option<ContextRecord> = sqlx::query_as!(
        ContextRecord,
        r#"SELECT id, user_id, name, position,
           created_at as "created_at: DateTime<Utc>"
           FROM contexts WHERE id = $1"#,
        context_id.as_uuid(),
    )
    .fetch_optional(pool)
    .await?;

    Ok(record.map(|r: ContextRecord| r.into_domain()))
}

pub async fn update_context_name(
    pool: &PgPool,
    context_id: &ContextId,
    name: &ContextName,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE contexts SET name = $1 WHERE id = $2"#,
        name.as_str(),
        context_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn delete_context(pool: &PgPool, context_id: &ContextId) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM contexts WHERE id = $1"#,
        context_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn get_max_position(pool: &PgPool, user_id: &UserId) -> Result<i32, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COALESCE(MAX(position), -1) as "max_pos!" FROM contexts WHERE user_id = $1"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.max_pos)
}

